import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TextInput,
  Button,
  Alert,
  StyleSheet,
  ActivityIndicator,
  SafeAreaView,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import RNBioMetrics from 'react-native-biometrics';

// --- HomeScreen Component ---
const HomeScreen = ({ onLogout }) => {
  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Welcome Home!</Text>
      <Text style={styles.subtitle}>You are successfully authenticated.</Text>
      <Button title="Logout" onPress={onLogout} color="#dc3545" />
    </SafeAreaView>
  );
};

// --- LoginScreen Component ---
const LoginScreen = ({ onAuthenticationSuccess }) => {
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const CORRECT_PASSWORD = 'password123'; // Replace with a real password check

  useEffect(() => {
    checkBiometrics();
  }, []);

  const checkBiometrics = async () => {
    try {
      const { available, biometryType } = await RNBioMetrics.isSensorAvailable();
      if (available) {
        setBiometricsAvailable(true);
        setBiometricType(biometryType);
        promptBiometrics();
      } else {
        setShowPasswordInput(true);
      }
    } catch (error) {
      console.error('Error checking biometrics:', error);
      setShowPasswordInput(true);
    } finally {
      setIsLoading(false);
    }
  };

  const promptBiometrics = async () => {
    try {
      const { success } = await RNBioMetrics.simplePrompt({
        promptMessage: `Confirm your ${biometricType === 'FaceID' ? 'Face ID' : 'fingerprint'} to authenticate`,
      });
      if (success) {
        onAuthenticationSuccess();
      } else {
        Alert.alert(
          'Authentication Failed',
          'Biometric authentication failed or was cancelled. Please try again or use password.',
          [
            { text: 'Try Again', onPress: () => promptBiometrics() },
            { text: 'Use Password', onPress: () => setShowPasswordInput(true) },
          ],
        );
      }
    } catch (error) {
      console.error('Biometric prompt error:', error);
      Alert.alert(
        'Biometric Error',
        'Could not start biometric authentication. Please use password.',
      );
      setShowPasswordInput(true);
    }
  };

  const handlePasswordLogin = () => {
    if (password === CORRECT_PASSWORD) {
      onAuthenticationSuccess();
    } else {
      Alert.alert('Login Failed', 'Incorrect password.');
    }
  };

  if (isLoading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#007bff" />
        <Text style={styles.loadingText}>Checking authentication status...</Text>
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <Text style={styles.title}>Login</Text>

      {biometricsAvailable && !showPasswordInput && (
        <View style={styles.biometricPrompt}>
          <Text style={styles.subtitle}>
            Authenticate with your {biometricType === 'FaceID' ? 'Face ID' : 'fingerprint'}
          </Text>
          <Button
            title={`Use ${biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}`}
            onPress={promptBiometrics}
            color="#007bff"
          />
          <Button
            title="Use Password Instead"
            onPress={() => setShowPasswordInput(true)}
            color="#6c757d"
            style={styles.switchButton}
          />
        </View>
      )}

      {showPasswordInput && (
        <View style={styles.passwordInputContainer}>
          <Text style={styles.subtitle}>Enter your password</Text>
          <TextInput
            style={styles.input}
            placeholder="Password"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            autoCapitalize="none"
          />
          <Button title="Login with Password" onPress={handlePasswordLogin} color="#28a745" />
          {biometricsAvailable && (
            <Button
              title={`Back to ${biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}`}
              onPress={() => setShowPasswordInput(false)}
              color="#6c757d"
              style={styles.switchButton}
            />
          )}
        </View>
      )}

      {!biometricsAvailable && showPasswordInput && (
        <View style={styles.passwordInputContainer}>
          <Text style={styles.subtitle}>
            Biometrics not available. Please login with password.
          </Text>
          <TextInput
            style={styles.input}
            placeholder="Password"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            autoCapitalize="none"
          />
          <Button title="Login with Password" onPress={handlePasswordLogin} color="#28a745" />
        </View>
      )}
    </SafeAreaView>
  );
};

// --- Main App Component ---
const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkAuthStatus();
  }, []);

  const checkAuthStatus = async () => {
    try {
      const authenticated = await AsyncStorage.getItem('authenticated');
      if (authenticated === 'true') {
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('Error checking auth status from AsyncStorage:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuthenticationSuccess = async () => {
    try {
      await AsyncStorage.setItem('authenticated', 'true');
      setIsAuthenticated(true);
    } catch (error) {
      console.error('Error storing auth status to AsyncStorage:', error);
      Alert.alert('Error', 'Could not save authentication status.');
    }
  };

  const handleLogout = async () => {
    try {
      await AsyncStorage.removeItem('authenticated');
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Error removing auth status from AsyncStorage:', error);
      Alert.alert('Error', 'Could not clear authentication status.');
    }
  };

  if (isLoading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#007bff" />
        <Text style={styles.loadingText}>Loading app...</Text>
      </View>
    );
  }

  return isAuthenticated ? (
    <HomeScreen onLogout={handleLogout} />
  ) : (
    <LoginScreen onAuthenticationSuccess={handleAuthenticationSuccess} />
  );
};

